// ── shared state via sessionStorage ──
const State = {
  set(key, val) { sessionStorage.setItem('apex_'+key, JSON.stringify(val)); },
  get(key)      { try { return JSON.parse(sessionStorage.getItem('apex_'+key)); } catch(e){ return null; } },
  clear()       { ['car','circuit','result'].forEach(k => sessionStorage.removeItem('apex_'+k)); }
};
